svg.script:
(function() {
  var isDark  = false;
  var isPrint = false;
  var svg     = document.getElementById('root');

  /* Dark-mode gradient swaps: [elementId, lightGradId, darkGradId] */
  var gradSwaps = [
    ['bar-g1',   'g1',   'g1d'  ],
    ['bar-g2',   'g2',   'g2d'  ],
    ['bar-g3',   'g3',   'g3d'  ],
    ['bar-g4',   'g4',   'g4d'  ],
    ['bar-g5',   'g5',   'g5d'  ],
    ['bar-g6',   'g6',   'g6d'  ],
    ['bar-g7',   'g7',   'g7d'  ],
    ['bar-goth', 'goth', 'gothd'],
  ];

  function applyDarkGrads(dark) {
    gradSwaps.forEach(function(s) {
      var el = document.getElementById(s[0]);
      if (el) el.setAttribute('fill', 'url(#' + (dark ? s[2] : s[1]) + ')');
    });
  }

  document.getElementById('dark-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (svg.classList.toggle('dark')) { isDark = true;  thumb.setAttribute('cx','52'); lbl.textContent='Light'; }
    else                              { isDark = false; thumb.setAttribute('cx','16'); lbl.textContent='Dark';  }
    applyDarkGrads(isDark);
  });

  document.getElementById('print-toggle').addEventListener('click', function() {
    isPrint = !isPrint;
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (isPrint) { svg.classList.add('print');    thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else         { svg.classList.remove('print'); thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  /* ── URL param: ?theme=dark|light sets initial mode ── */
  (function() {
    var params = new URLSearchParams(window.location.search);
    if (params.get('theme') === 'dark') {
      svg.classList.add('dark');
      var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
      applyDarkGrads(true);
    }
  })();

})();
